//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function () {
  if (lc_con_districtCd.getValue() == "") {
    await $c.win.alert($p, "권역을 선택해 주십시오.");
    lc_con_districtCd.focus();
    return;
  }
  if (lc_con_wrkMthdCd.getValue() == "") {
    await $c.win.alert($p, "작업방법을 선택해 주십시오.");
    lc_con_wrkMthdCd.focus();
    return;
  }
  if (ica_con_adptDt.getValue() == "") {
    await $c.win.alert($p, "적용일자를 선택해 주십시오.");
    ica_con_adptDt.focus();
    return;
  }
  $c.sbm.execute($p, sbm_retrieve);
};

//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.f_Save = async function () {
  scwin.pos_grid = ds_master.getRowPosition();
  let setGoods = ds_master.getCellData(scwin.pos_grid, "goodsCd");
  //변경한 데이터가 있는지 체크한다. 

  if (ds_master.getModifiedIndex().length == 0) {
    await $c.win.alert($p, MSG_CM_ERR_001, ["하역노임기본요율"]);
    return;
  }
  for (let i = 0; i < ds_master.getRowCount(); i++) {
    if (ds_master.getCellData(i, "adptStDt") == "") {
      await $c.win.alert($p, "요율의 적용시작일자를 입력해 주세요.");
      gr_master.setFocusedCell(i, "adptStDt");
      return false;
    }
    if (ds_master.getCellData(i, "adptEndDt") == "") {
      await $c.win.alert($p, "요율의 적용종료일자를 입력해 주세요.");
      gr_master.setFocusedCell(i, "adptEndDt");
      return false;
    }
  }
  let chkAlert = await $c.win.confirm($p, "저장하시겠습니까?");
  if (chkAlert) {
    $c.sbm.execute($p, sbm_save);
  }
};

//-------------------------------------------------------------------------
// 신규
//-------------------------------------------------------------------------
scwin.f_Create = function () {
  scwin.f_openCommonPopUp(3, '', '', 'T', 'T');
};

//-------------------------------------------------------------------------
// 삭제
//-------------------------------------------------------------------------
scwin.f_Delete = async function () {
  let row = ds_master.getRowPosition();
  let goodsCd = ds_master.getCellData(row, "goodsCd");
  let chkAlert = await $c.win.confirm($p, "선택한 품명 [ " + ds_master.getCellData(row, "goodsNm") + " ] 에 대한 요율을 삭제하시겠습니까?");
  if (chkAlert) {
    for (let i = 0; i < ds_master.getRowCount(); i++) {
      if (ds_master.getCellData(i, "goodsCd") == goodsCd) {
        ds_master.deleteRow(i);
      }
    }
  }
};

