scwin.f_Cancel = async function () {
  let chkAlert = await $c.win.confirm($p, "취소하시겠습니까?");
  if (chkAlert) {
    //ds_master.Undo(ds_master.RowPosition);
    $c.data.undoRow($p, ds_master);
  }
};

//-------------------------------------------------------------------------
// 공통 Popup 처리 : Gubun Code 에 따른 공통 Popup 을 호출한다.
//-------------------------------------------------------------------------
scwin.f_openCommonPopUp = async function (disGubun, pCode, pName, pClose, pAllSearch) {
  switch (disGubun) {
    case 1:
      // 품명 조건검색 팝업
      udc_con_goodsCd.cfCommonPopUp(scwin.callbackCommGoodsInfo1, pCode.trim(), pName, pClose, null, null, null, null, null, null, null, null, null, null, pAllSearch, null);
      break;
    case 2:
      // 품명 조건검색 팝업
      udc_con_goodsCd.cfCommonPopUp(scwin.callbackCommGoodsInfo2, pCode.trim(), pName, pClose, null, null, null, null, null, null, null, null, null, null, pAllSearch, null);
      break;
    case 3:
      // 품명 조건검색 팝업
      udc_con_goodsCd.cfCommonPopUpAsync(null, pCode.trim(), pName, pClose, null, null, null, null, null, null, null, null, null, null, pAllSearch, null).then(rtnList => scwin.callbackCommGoodsInfo3(rtnList));
      break;
    default:
      break;
  }
};

//-------------------------------------------------------------------------
// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopUp = function (inObj, pairObj, disGubun, isCode) {
  // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
  if (!$c.gus.cfCanOpenPopup($p, inObj, pairObj)) {
    return;
  }

  // 짝이 되는 오브젝트의 값 제거
  $c.gus.cfClearPairObj($p, pairObj);

  // 검색어 세팅
  let pVal = $c.gus.cfGetValue($p, inObj);
  if (isCode == null || isCode == true) {
    scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T'); // inObj가 코드 필드일 경우 팝업
  } else {
    scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T'); // inObj가 코드명 필드일 경우 팝업
  }
};

//-------------------------------------------------------------------------
// 기본단위코드와 할증단위코드 동기화
//-------------------------------------------------------------------------
scwin.f_SelectUnitCd = function (row, colid) {
  if (colid == "basisUnitCd") {
    ds_master.setCellData(row, "scBasisUnitCd", ds_master.getCellData(row, "basisUnitCd"));
  }
};

//-------------------------------------------------------------------------
// 그리드에서 달력팝업 호출
//-------------------------------------------------------------------------
scwin.f_CalendarOpenPopup = function (row, colid) {
  if (colid == "goodsNm") {
    scwin.f_openCommonPopUp(2, "", "", "T", "T");
  }
  if (colid == "goodsCd") {
    scwin.f_openCommonPopUp(2, ds_master.getCellData(row, "goodsCd"), "", "T", "T");
  }
};
scwin.f_changeImage = function (Colid) {};
scwin.f_toExcel = function () {
  const options = {
    "fileName": "하역노임 기본요율.xlsx",
    "sheetName": "하역노임 기본요율",
    "startRowIndex": 3,
    "startColumnIndex": 0,
    "colMerge": "true"
  };
  let totlaCol = gr_master.getTotalCol();
  let colSpan = 0;
  for (let idx = 0; idx < totlaCol; ++idx) {
    if (gr_master.getColumnVisible(idx)) {
      ++colSpan;
    }
  }
  const infoArr = [{
    "rowIndex": 0,
    "colIndex": 0,
    "rowSpan": 1,
    "colSpan": colSpan,
    "text": "하역노임 기본요율",
    "textAlign": "center",
    "drawBorder": "false",
    "bgColor": "yellow",
    "fontSize": "16px"
  }];
  $c.data.downloadGridViewExcel($p, gr_master, options, infoArr);
};

